2 Prepare data for plotting

soy_df &lt;- py$soy_df

yield &lt;- soy_df |&gt;
  mutate(produto = "Soybean") |&gt;
  # Split "1976/77" into "1976" and "77"
  separate(safra, into = c("year_start", "year_end"), sep = "/", remove = FALSE) |&gt;
  # Logic: If year_end is 00-25, it's 2000s. If it's 76-99, it's 1900s.
  mutate(year = as.numeric(year_end),
         year = ifelse(year &lt;= 25, 2000 + year, 1900 + year)) |&gt;
  group_by(produto, year) |&gt;
  summarize(mean_yield = mean(produtividade_kg_ha, na.rm = TRUE)) |&gt;
  ungroup()

2 Prepare data for plotting

## Define the 'North' 
north_high_income_asia &lt;- c("JPN", "KOR", "TWN", "SGP", "ISR")
north_fsu_states       &lt;- c("SVU", "RUS", "UKR", "BLR", "MDA", "KAZ")
north_anglo_oceania    &lt;- c("USA", "CAN", "AUS", "NZL")

# Process the data 
df_processed &lt;- df |&gt;
  filter(
    Variable == "Outall_Q",
    nchar(ISO3) == 3
  ) |&gt; 
  mutate(
    Category = case_when(
      ISO3 %in% north_anglo_oceania ~ "Global North",
      ISO3 %in% north_high_income_asia ~ "Global North",
      ISO3 %in% north_fsu_states ~ "Global North",
      Region %in% c("EUROPE", "Former Soviet Union", "Transition countries") ~ "Global North",
      TRUE ~ "Global South"
    ),
    Value_Billions = Value / 1000000
  ) |&gt;
  group_by(Year, Category) |&gt;
  summarise(
    Total = sum(Value_Billions, na.rm = TRUE), 
    .groups = "drop"
  )

# World Total Line
world_total &lt;- df_processed |&gt;
  group_by(Year) |&gt;
  summarise(
    Total = sum(Total), 
    Category = "World total"
  )

final_df &lt;- bind_rows(df_processed, world_total)

# Create labels for the end of the lines
line_labels &lt;- final_df |&gt;
  filter(Year == max(Year))

2 Prepare data for plotting

# Processing the Python data frame
df_mosaic_final &lt;- py$df_clean |&gt;
  filter(!is.na(valor), valor &gt; 0) |&gt;
  mutate(
    # Simplified categories (no subcategories)
    category = case_when(
      str_detect(categoria, fixed("agroflorestais", ignore_case = TRUE)) ~ "Agroforestry",
      str_detect(categoria, fixed("Lavouras", ignore_case = TRUE)) ~ "Croplands",
      str_detect(categoria, fixed("Pastagens", ignore_case = TRUE)) ~ "Pasturelands",
      str_detect(categoria, fixed("Matas", ignore_case = TRUE)) | 
        str_detect(categoria, fixed("florestas", ignore_case = TRUE)) ~ "Forests",
      TRUE ~ "Others"
    )
  ) |&gt;
  # Grouping by State (localidade) and Category
  group_by(localidade, category) |&gt;
  summarise(valor = sum(valor), .groups = "drop") |&gt;
  filter(category != "Agroforestry") |&gt;
  filter(category != "Others")

2 Prepare data for plotting

target_order &lt;- rev(c(
  "Forest", 
  "Herbaceous vegetation", 
  "Agriculture", 
  "Non vegetated area", 
  "Water bodies"
))

df_sankey &lt;- df |&gt;
  mutate(
    area_mha = as.numeric(area) / 1000000,
    across(c(start, end), ~case_when(
      . == "Herbaceous and Shrubby Vegetation" ~ "Herbaceous vegetation",
      . == "Farming" ~ "Agriculture",
      . == "Water and Marine Environment" ~ "Water bodies",
      TRUE ~ .
    ))
  ) |&gt;
  make_long(start, end, value = area_mha) |&gt;
  group_by(x, node) |&gt;
  mutate(label_full = paste0(node, "\n", round(sum(value, na.rm = TRUE), 1), " Mha")) |&gt;
  ungroup() |&gt;
  # Now levels = target_order will find the shortened names correctly
  mutate(
    node = factor(node, levels = target_order),
    next_node = factor(next_node, levels = target_order)
  )

2 Prepare data for plotting

df_long &lt;- df_age |&gt;
  mutate(total = Men + Women) |&gt;
  mutate(
    Men = (Men / sum(total)) * 100,
    Women = (Women / sum(total)) * 100
  ) |&gt;
  pivot_longer(cols = c(Men, Women), names_to = "Gender", values_to = "Percentage") |&gt;
  mutate(
    plot_value = ifelse(Gender == "Men", -Percentage, Percentage),
    age_group = factor(age_group, levels = c("Less than 25 years", "Between 25 and 34 years", "Between 35 and 44 years", 
                                           "Between 45 and 54 years", "Between 55 and 64 years", "Between 65 and 74 years", "More than 75 years"))
  )

2 Prepare data for plotting

df_radial &lt;- raw_data_2024 |&gt;
  group_by(crop) |&gt;
  mutate(
    total_val = value[region == "Brazil"],
    pct = (value / total_val) * 100
  ) |&gt;
  filter(region != "Brazil") |&gt; 
  slice_max(order_by = pct, n = 3, with_ties = FALSE) |&gt;
  # Add Others
  group_modify(~ add_row(.x, region = "Others", pct = 100 - sum(.x$pct))) |&gt;
  arrange(crop, region == "Others", desc(pct)) |&gt; 
  group_modify(~ add_row(.x, region = "GAP", pct = NA)) |&gt; 
  ungroup() |&gt;
  mutate(spoke_id = row_number()) |&gt;
  mutate(
    fill_color = case_when(
      region == "GAP"    ~ NA_character_,
      crop == "Soybean"   ~ col_soy,
      crop == "Coffee"    ~ col_coffee,
      crop == "Sugarcane" ~ col_sugar,
      crop == "Orange"    ~ col_orange,
      crop == "Maize"     ~ col_maize,
      TRUE ~ "grey90"
    ),
    label_text = ifelse(region == "Others", "Others", 
                        paste0(region, " (", round(pct, 1), "%)"))
  )

df_labels &lt;- df_radial |&gt;
  filter(region != "GAP") |&gt;
  mutate(
    angle = 90 - 360 * (spoke_id - 0.5) / max(df_radial$spoke_id),
    hjust = ifelse(angle &lt; -90, 1, 0),
    angle = ifelse(angle &lt; -90, angle + 180, angle)
  )

2 Prepare data for plotting

ag_machinery_clean &lt;- ag_machinery |&gt;
  filter(`Variável` == "Número de estabelecimentos agropecuários",
    `Sexo do produtor` == "Total",
    `Tipologia` == "Total",
    `Classe de idade do produtor` == "Total"
         ) |&gt;
  select(`Tratores, implementos e máquinas existentes no estabelecimento agropecuário`, Valor)

# totals
total_est &lt;- ag_machinery_clean |&gt; 
  filter(`Tratores, implementos e máquinas existentes no estabelecimento agropecuário` == "Total") |&gt; 
  pull(Valor)

df_plot &lt;- ag_machinery_clean |&gt;
  filter(`Tratores, implementos e máquinas existentes no estabelecimento agropecuário` != "Total") |&gt;
  mutate(
    item = case_match(
      `Tratores, implementos e máquinas existentes no estabelecimento agropecuário`,
      "Tratores" ~ "Tractors",
      "Semeadeiras/plantadeiras" ~ "Seeders/Planters",
      "Colheitadeiras" ~ "Harvesters",
      "Adubadeiras e/ou distribuidoras de calcário" ~ "Fertilizer Spreaders",
      .default = `Tratores, implementos e máquinas existentes no estabelecimento agropecuário`
    ),
    # Calculate percentages
    percent = (Valor / total_est) * 100,
    rest = 100 - percent
  )

2 Prepare data for plotting

# Data prep
farmer_gender_clean &lt;- farmer_gender |&gt;
  filter(`Condição legal das terras` == "Total", 
         `Cor ou raça do produtor` == "Total",
         `Condição do produtor em relação às terras` == "Total",
         `Unidade de Medida` == "Unidades") |&gt;
  filter(`Sexo do produtor` %in% c("Homens", "Mulheres", "Não se aplica")) |&gt;
  mutate(valor_num = as.numeric(as.character(Valor))) |&gt;
  group_by(`Sexo do produtor`) |&gt;
  summarise(total_valor = sum(valor_num)) |&gt;
  mutate(
    percentual = (total_valor / sum(total_valor)) * 100,
    squares = as.integer(round(percentual))
  )

# Icon adjustments

img_man   &lt;- "icons/farmer_man.png"
img_woman &lt;- "icons/farmer_woman.png"

plot_data &lt;- expand.grid(
    x = 1:10,
    y = 1:10
  ) %&gt;%
  as_tibble() %&gt;%
  arrange(x, y) %&gt;%
  mutate(img = case_when(
    row_number() &lt;= 81 ~ img_man,
    TRUE ~ img_woman
  )) %&gt;%
  mutate(
    icon_color = if_else(img == img_man, "#2D6A4F", "#dda15e")
  )
